THOUGHT: The crash is due to an assertion that checks VPlan vs legacy cost-model VF. The reproducer triggers extra simplifications in VPlan (dropPoisonGeneratingRecipes on predicated path), but planContainsAdditionalSimplifications fails to recognize them because it ignores instructions skipped by VPCostContext. I should locate skipCostComputation usage/definition and adjust planContainsAdditionalSimplifications to treat instructions not represented in the plan as additional simplifications regardless of skipCostComputation, which will justify the VF disagreement and avoid the assert.

```bash
grep -nR "skipCostComputation(" llvm/lib/Transforms/Vectorize | sed -n '1,120p' && sed -n '7310,7335p' llvm/lib/Transforms/Vectorize/LoopVectorize.cpp && applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
-                                    TheLoop](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
-      if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
-        return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
-    });
-  });
+  // Note: Previously, instructions not represented in the VPlan but skipped by
+  // CostCtx were ignored here. However, VPlan can deliberately drop or predicate
+  // potentially poison-generating instructions (e.g. via
+  // VPlanTransforms::dropPoisonGeneratingRecipes) which the legacy cost-model
+  // still accounts for. In such cases, these "skipped" instructions are indeed
+  // additional simplifications that can legitimately cause VF decisions to
+  // differ. Therefore, consider any instruction not present in the VPlan as an
+  // additional simplification, regardless of whether CostCtx skips it.
+  return any_of(TheLoop->blocks(), [&SeenInstrs, TheLoop](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs, TheLoop, BB](Instruction &I) {
+      if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
+        return false;
+      return !SeenInstrs.contains(&I);
+    });
+  });
 }
 #endif
*** End Patch
EOF
```

