messages.content:
THOUGHT: The crash stems from an assertion firing when the VPlan cost model selects a different VF than the legacy model, unless the VPlan contains “additional simplifications.” The reproducer has a predicated wide shift which VPlan can drop/predicate, but planContainsAdditionalSimplifications currently ignores instructions skipped by the VPlan cost context, missing legitimate simplifications. I will patch planContainsAdditionalSimplifications to conservatively treat any original loop instruction not represented in the VPlan as an additional simplification, regardless of CostCtx. Then I will run the patch submission.

```bash
awk '
  BEGIN{skip=0}
  /return any_of\(TheLoop->blocks\(/ {
    print "  // Return true if the loop contains any instructions that are not also part of";
    print "  // the VPlan. This indicates that the VPlan contains extra simplifications.";
    print "  return any_of(TheLoop->blocks(), [&SeenInstrs, TheLoop](BasicBlock *BB) {";
    print "    return any_of(*BB, [&SeenInstrs, TheLoop, BB](Instruction &I) {";
    print "      if (isa<PHINode>(&I) && BB == TheLoop->getHeader())";
    print "        return false;";
    print "      return !SeenInstrs.contains(&I);";
    print "    });";
    print "  });";
    skip=2; next
  }
  skip>0 {
    if ($0 ~ /\}\);/) { skip--; }
    next
  }
  {print}
' llvm/lib/Transforms/Vectorize/LoopVectorize.cpp > /tmp/LoopVectorize.cpp.new && mv /tmp/LoopVectorize.cpp.new llvm/lib/Transforms/Vectorize/LoopVectorize.cpp && submit-patch
```

